// Solution
#include <iostream>
#include <vector>

using namespace std;

class Solution {
public:
    vector<int> productPairs(vector<int>& nums);
};

vector<int> Solution::productPairs(vector<int>& nums) {
    int n = nums.size();
    vector<int> result(n);
    result[0] = 1;
    for (int i = 1; i < n; i++) {
        result[i] = 1;
        for (int j = 0; j < i; j++) {
            result[i] *= nums[j];
        }
    }
    return result;
}

int main() {
    Solution solution;
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) {
        cin >> nums[i];
    }
    vector<int> result = solution.productPairs(nums);
    for (int i = 0; i < n; i++) {
        cout << result[i] << ' ';;
    }
    cout << endl;
    return 0;
}

