public class Solution {
public static void main(String[] args) {
    Scanner scanner = new Scanner(System.in);
    int n = scanner.nextInt();
    int[] nums = new int[n];
    for (int i = 0; i < n; i++) {
        nums[i] = scanner.nextInt();
    }
    int[] result = productPairs(nums);
    for (int i = 0; i < n; i++) {
        System.out.print(result[i] + ' ');
    }
    System.out.println();
}

public static int[] productPairs(int[] nums) {
    int n = nums.length;
    int[] result = new int[n];
    result[0] = 1;
    for (int i = 1; i < n; i++) {
        result[i] = 1;
        for (int j = 0; j < i; j++) {
            result[i] *= nums[j];
        }
    }
    return result;
}

