// Solution
import sys
from typing import List

class Solution:
    def productPairs(self, nums: List[int]) -> List[int]:
        n = len(nums)
        result = [1] * n
        for i in range(1, n):
            result[i] = 1
            for j in range(i):
                result[i] *= nums[j]
        return result

def main():
    solution = Solution()
    n = int(input())
    nums = [int(x) for x in input().split()]
    result = solution.productPairs(nums)
    print(' '.join(map(str, result)))

if __name__ == '__main__':
    main()

