    let n = nums.length;
    let result = new Array(n);
    result[0] = 1;
    for (let i = 1; i < n; i++) {
        result[i] = 1;
        for (let j = 0; j < i; j++) {
            result[i] *= nums[j];
        }
    }
    return result;
}

